package tests.panels.arming;

import base.TestBase;
import org.testng.annotations.Test;

// EX-T1002
public class ArmStayGroupTest extends TestBase {

    @Test(groups = {"arm-stay", "group-01"})
    public void testArmStayFromKeypad() {

        REPORT("Panel is in DISARMED state");
        panel.assertState(PanelState.DISARMED);

        REPORT("User enters ARM STAY code on keypad");
        keypad.enterCode(config.getMasterCode());
        keypad.pressArmStay();

        REPORT("Panel transitions to ARMED STAY immediately");
        panel.assertState(PanelState.ARMED_STAY);

        REPORT("Interior motion sensors are bypassed");
        sensorManager.assertBypassed(SensorType.INTERIOR_MOTION);

        // Partial: triggers entry sensor and confirms countdown starts,
        // but does not validate that disarming mid-countdown suppresses alarm.
        // TODO: add disarmBeforeEntryDelay assertion — see EX-T1002 step 5
        REPORT("Entry sensor triggers — entry delay countdown begins");
        sensor.triggerEntry(SensorType.DOOR_WINDOW);
        panel.assertEntryDelayActive();

        panel.disarm(config.getMasterCode());
    }
}
